import React from 'react';

export default function ParticipantsList({ participants = [] }){
  return (
    <div>
      <strong>Учасники ({participants.length}):</strong>
      <ul>
        {participants.map((p, i) => (
          <li key={i}>{p}</li>
        ))}
      </ul>
    </div>
  );
}
